package genxsolution.vms.vmsbackend.employee_hr_management.ration_policy.service;
import genxsolution.vms.vmsbackend.employee_hr_management.exception.HrResourceNotFoundException; import genxsolution.vms.vmsbackend.employee_hr_management.ration_policy.dto.*; import genxsolution.vms.vmsbackend.employee_hr_management.ration_policy.mapper.RationPolicyMapper; import genxsolution.vms.vmsbackend.employee_hr_management.ration_policy.repository.RationPolicyRepository; import org.springframework.stereotype.Service; import java.util.*;
@Service public class RationPolicyService { private final RationPolicyRepository repository; private final RationPolicyMapper mapper; public RationPolicyService(RationPolicyRepository repository,RationPolicyMapper mapper){this.repository=repository;this.mapper=mapper;} public List<RationPolicyResponse> list(UUID companyId){ return repository.findAll(companyId).stream().map(mapper::toResponse).toList(); } public RationPolicyResponse getById(UUID id){ return repository.findById(id).map(mapper::toResponse).orElseThrow(() -> new HrResourceNotFoundException("RationPolicy", id.toString())); } public RationPolicyResponse create(RationPolicyUpsertRequest r){ return mapper.toResponse(repository.create(r)); } public RationPolicyResponse update(UUID id,RationPolicyUpsertRequest r){ return repository.update(id,r).map(mapper::toResponse).orElseThrow(() -> new HrResourceNotFoundException("RationPolicy", id.toString())); } public void delete(UUID id){ if(!repository.delete(id)) throw new HrResourceNotFoundException("RationPolicy", id.toString()); } }
